<template><el-container class="layout"><el-aside width="230px"><h2>意图驱动网络策略管理系统</h2><el-menu router :default-active="$route.path"><el-menu-item index="/">首页</el-menu-item><el-menu-item index="/situation">态势感知</el-menu-item><el-menu-item v-if="user.role!=='auditor'" index="/regions">区域管理</el-menu-item><el-menu-item v-if="user.role!=='auditor'" index="/orgs">组织管理</el-menu-item><el-menu-item v-if="user.role!=='auditor'" index="/apps">应用管理</el-menu-item><el-menu-item v-if="user.role!=='auditor'" index="/intents">意图策略管理</el-menu-item><el-menu-item v-if="user.role==='auditor'" index="/logs">日志审计</el-menu-item></el-menu></el-aside><el-container><el-header><b>{{$route.meta.title||'首页'}}</b><span>{{user.name}}（{{roleName}}）</span><el-button @click="logout">退出</el-button></el-header><el-main><router-view/></el-main></el-container></el-container></template>
<script setup>import{computed}from'vue';import{useRouter}from'vue-router';const router=useRouter();const user=JSON.parse(localStorage.getItem('user'));const roleName=computed(()=>({admin:'管理员',operator:'操作员',auditor:'审计员'}[user.role]));function logout(){localStorage.removeItem('user');router.push('/login')}</script>
